var templateId = current.getValue("tasker_process_template") || '';
// STRY0146507 - Certification Failed Test Resutls - NOT FIXING - Task permissions drives Task Response permissions
var grTemplate = new GlideRecord("x_153465_discovert_discover_routing_template");
var allow = false;
if(templateId !=''){
	if(grTemplate.get(templateId)){
		allow = grTemplate.canRead();
	}
}
answer = allow;
